import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const statusBadge = (status) => {
  const map = { confirmed: styles.badgeGreen, pending: styles.badgeYellow, cancelled: styles.badgeRed };
  return map[status] || '';
};

const ManageBookingsPage = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState('');

  const load = () => {
    setLoading(true);
    api.get('/bookings')
      .then((res) => setBookings(res.data?.data || []))
      .catch(() => setError('Failed to load bookings.'))
      .finally(() => setLoading(false));
  };

  useEffect(load, []);

  const updateStatus = async (id, status) => {
    try {
      await api.put(`/bookings/${id}`, { status });
      load();
    } catch { alert('Update failed.'); }
  };

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>📅 Manage Bookings</h1>
        {loading && <p>Loading…</p>}
        {error   && <p style={{ color: 'red' }}>{error}</p>}
        {!loading && !error && (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>User</th>
                <th>Package</th>
                <th>Date</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {bookings.length === 0 ? (
                <tr><td colSpan={5}>No bookings found.</td></tr>
              ) : bookings.map((b) => (
                <tr key={b._id}>
                  <td>{b.user?.name || b.user?.email || '—'}</td>
                  <td>{b.package?.name || '—'}</td>
                  <td>{new Date(b.createdAt).toLocaleDateString()}</td>
                  <td>
                    <span className={`${styles.badge} ${statusBadge(b.status)}`}>
                      {b.status}
                    </span>
                  </td>
                  <td className={styles.actions}>
                    {b.status === 'pending' && (
                      <button
                        className={`${styles.btnSm} ${styles.btnSuccess}`}
                        onClick={() => updateStatus(b._id, 'confirmed')}
                      >
                        Confirm
                      </button>
                    )}
                    {b.status !== 'cancelled' && (
                      <button
                        className={`${styles.btnSm} ${styles.btnDanger}`}
                        onClick={() => updateStatus(b._id, 'cancelled')}
                      >
                        Cancel
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
};

export default ManageBookingsPage;
